from collections import defaultdict


class Solution:
    def countPairs(self, nums):
        def variants(x):
            s = str(x)
            L = len(s)
            res = {x}
            for i in range(L):
                for j in range(i + 1, L):
                    lst = list(s)
                    lst[i], lst[j] = lst[j], lst[i]
                    res.add(int(''.join(lst)))
            return res

        buckets = defaultdict(list)
        count = 0
        for i, x in enumerate(nums):
            vs = variants(x)
            seen = set()
            for v in vs:
                if v in buckets:
                    for j in buckets[v]:
                        seen.add(j)
            count += len(seen)
            for v in vs:
                buckets[v].append(i)
        return count

