var countPairs = function(nums) {
    function variants(x) {
        const s = String(x);
        const L = s.length;
        const res = new Set([x]);
        for (let i = 0; i < L; i++) {
            for (let j = i + 1; j < L; j++) {
                const arr = s.split('');
                const tmp = arr[i]; arr[i] = arr[j]; arr[j] = tmp;
                res.add(parseInt(arr.join(''), 10));
            }
        }
        return res;
    }
    const buckets = new Map();
    let count = 0;
    for (let i = 0; i < nums.length; i++) {
        const vs = variants(nums[i]);
        const seen = new Set();
        for (const v of vs) {
            const arr = buckets.get(v);
            if (arr) for (const j of arr) seen.add(j);
        }
        count += seen.size;
        for (const v of vs) {
            if (!buckets.has(v)) buckets.set(v, []);
            buckets.get(v).push(i);
        }
    }
    return count;
};
